import { stringify } from '../utils/stringify';
import fs from 'fs';

const traceFile = 'axios_trace.log';

export function axiosTrace(data: any) {
  const traceFlag = process.env.E2E_TOKEN_FETCHER_TRACE_AXIOS;
  if (traceFlag && traceFlag != '0') {
    // console.log(data);
    fs.appendFileSync(traceFile, stringify(data) + '\n', 'utf-8');
  }
}
